// ─── DESKTOP NEWSPAPER GRID ───────────────────────────────────────────────────

function DesktopMainView({ onOpenQuestion, onOpenVoice, onCreate, onGoAbout, onGoArchive, onGoSaved, bookmarks, onBookmark }) {
  const [activeRing, setActiveRing] = useState("all");
  const [votes, setVotes]           = useState({});
  const [overlays, setOverlays]     = useState({});
  const [overlayOp, setOverlayOp]   = useState({});

  const fireVote = (id, v) => {
    if (overlays[id]) return;
    setVotes(p => ({ ...p, [id]: null }));
    setOverlays(o => ({ ...o, [id]: v }));
    setTimeout(() => setOverlayOp(o => ({ ...o, [id]: 1 })), 20);
    setTimeout(() => setOverlayOp(o => ({ ...o, [id]: 0 })), 1500);
    setTimeout(() => { setVotes(p => ({ ...p, [id]: v })); setOverlays(o => { const n = {...o}; delete n[id]; return n; }); }, 2000);
  };

  const filtered = (arr) => activeRing === "all" ? arr : arr.filter(x => x.ring === activeRing);
  const voiceList    = filtered(voices).sort((a, b) => b.upvotes - a.upvotes);
  const questionList = filtered(questions).sort((a, b) => (b.responses + b.directlyAffected) - (a.responses + a.directlyAffected));

  const lead       = voiceList[0];
  const featured   = voiceList.slice(1, 3);
  const standard   = voiceList.slice(3, 7);
  const smallVoices = voiceList.slice(7);
  const today = new Date().toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric", year: "numeric" });

  // ── Voice card components ──

  const LeadCard = ({ v }) => {
    const c = cat(v.category);
    return (
      <div onClick={() => onOpenVoice(v.id)} style={{ cursor: "pointer", position: "relative", height: 480, overflow: "hidden", background: v.gradient }}
        onMouseEnter={e => e.currentTarget.querySelector(".lead-overlay").style.opacity = "0.7"}
        onMouseLeave={e => e.currentTarget.querySelector(".lead-overlay").style.opacity = "0.55"}>
        {v.imageUrl && <img src={v.imageUrl} alt="" style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover" }} onError={e => e.target.style.display="none"} />}
        <div className="lead-overlay" style={{ position: "absolute", inset: 0, background: "linear-gradient(to bottom, rgba(0,0,0,0.1) 0%, rgba(0,0,0,0.75) 100%)", transition: "opacity 0.2s", opacity: 0.55 }} />
        <div style={{ position: "absolute", inset: 0, padding: "28px 32px", display: "flex", flexDirection: "column", justifyContent: "flex-end" }}>
          <div style={{ display: "flex", gap: 8, marginBottom: 14 }}>
            <span style={{ background: c.color, color: "white", padding: "3px 10px", borderRadius: 2, fontSize: 10, fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.8px" }}>{c.label}</span>
            <span style={{ background: "rgba(255,255,255,0.15)", color: "white", padding: "3px 10px", borderRadius: 2, fontSize: 10, fontWeight: 700, textTransform: "uppercase" }}>Voice</span>
            <span style={{ marginLeft: "auto", color: "rgba(255,255,255,0.6)", fontSize: 11, alignSelf: "center" }}>{v.readTime}</span>
          </div>
          <h1 style={{ fontFamily: "Playfair Display, serif", fontSize: 38, fontWeight: 900, lineHeight: 1.18, color: "white", marginBottom: 18, textShadow: "0 2px 8px rgba(0,0,0,0.3)" }}>{v.headline}</h1>
          <p style={{ fontSize: 15, color: "rgba(255,255,255,0.8)", lineHeight: 1.6, marginBottom: 20, maxWidth: 640 }}>{v.preview}</p>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <Avatar categoryKey={v.category} size={32} />
            <span style={{ fontFamily: "Playfair Display, serif", fontSize: 14, fontWeight: 700, fontStyle: "italic", color: "white" }}>{v.signature}</span>
            <span style={{ fontSize: 12, color: "rgba(255,255,255,0.55)" }}>· {v.region}</span>
            <span style={{ marginLeft: "auto", fontSize: 13, color: "rgba(255,255,255,0.55)" }}>▲ {fmt(v.upvotes)}</span>
            <span onClick={e => { e.stopPropagation(); onBookmark({ id: v.id, type: "voice" }); }}
              style={{ cursor: "pointer", fontSize: 18, color: bookmarks.some(b => b.id === v.id && b.type === "voice") ? "#F5C842" : "rgba(255,255,255,0.4)" }}>
              {bookmarks.some(b => b.id === v.id && b.type === "voice") ? "★" : "☆"}
            </span>
          </div>
        </div>
      </div>
    );
  };

  const FeaturedCard = ({ v }) => {
    const c = cat(v.category);
    return (
      <div onClick={() => onOpenVoice(v.id)} style={{ cursor: "pointer", display: "flex", flexDirection: "column", height: "100%", overflow: "hidden", background: "#FDFAF5" }}
        onMouseEnter={e => e.currentTarget.style.opacity = "0.9"}
        onMouseLeave={e => e.currentTarget.style.opacity = "1"}>
        <div style={{ height: 180, background: v.gradient, position: "relative", flexShrink: 0 }}>
          {v.imageUrl && <img src={v.imageUrl} alt="" style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover" }} onError={e => e.target.style.display="none"} />}
          <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to bottom, rgba(0,0,0,0.05), rgba(0,0,0,0.65))" }} />
          <div style={{ position: "absolute", bottom: 12, left: 14, display: "flex", gap: 6 }}>
            <span style={{ background: c.color, color: "white", padding: "2px 8px", borderRadius: 2, fontSize: 9, fontWeight: 800, textTransform: "uppercase" }}>{c.label}</span>
          </div>
        </div>
        <div style={{ flex: 1, padding: "16px 18px", borderLeft: `3px solid ${c.color}`, display: "flex", flexDirection: "column" }}>
          <h2 style={{ fontFamily: "Playfair Display, serif", fontSize: 19, fontWeight: 700, lineHeight: 1.3, color: "#1A1208", marginBottom: 10, flex: 1 }}>{v.headline}</h2>
          <p style={{ fontSize: 12, color: "#7A7068", lineHeight: 1.6, marginBottom: 12 }}>{v.preview.slice(0, 120)}…</p>
          <div style={{ display: "flex", alignItems: "center", gap: 8, paddingTop: 10, borderTop: "1px solid #EAE4DA" }}>
            <span style={{ fontFamily: "Playfair Display, serif", fontSize: 12, fontWeight: 700, fontStyle: "italic", color: "#1A1208" }}>{v.signature}</span>
            <span style={{ fontSize: 10, color: "#C0B8AE", marginLeft: "auto" }}>▲ {fmt(v.upvotes)}</span>
          </div>
        </div>
      </div>
    );
  };

  const StandardCard = ({ v }) => {
    const c = cat(v.category);
    return (
      <div onClick={() => onOpenVoice(v.id)} style={{ cursor: "pointer", background: "#FDFAF5", overflow: "hidden" }}
        onMouseEnter={e => e.currentTarget.style.opacity = "0.9"}
        onMouseLeave={e => e.currentTarget.style.opacity = "1"}>
        <div style={{ height: 160, background: v.gradient, position: "relative" }}>
          {v.imageUrl && <img src={v.imageUrl} alt="" style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover" }} onError={e => e.target.style.display="none"} />}
          <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to bottom, rgba(0,0,0,0.0), rgba(0,0,0,0.6))" }} />
          <span style={{ position: "absolute", bottom: 10, left: 12, background: c.color, color: "white", padding: "2px 8px", borderRadius: 2, fontSize: 9, fontWeight: 800, textTransform: "uppercase" }}>{c.label}</span>
        </div>
        <div style={{ padding: "14px 16px", borderLeft: `3px solid ${c.color}` }}>
          <h3 style={{ fontFamily: "Playfair Display, serif", fontSize: 16, fontWeight: 700, lineHeight: 1.35, color: "#1A1208", marginBottom: 10 }}>{v.headline}</h3>
          <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
            <span style={{ fontFamily: "Playfair Display, serif", fontSize: 11, fontWeight: 700, fontStyle: "italic", color: "#5A4A3A" }}>{v.signature}</span>
            <span style={{ fontSize: 10, color: "#B8AFA4", marginLeft: "auto" }}>▲ {fmt(v.upvotes)}</span>
          </div>
        </div>
      </div>
    );
  };

  const SmallVoiceCard = ({ v }) => {
    const c = cat(v.category);
    return (
      <div onClick={() => onOpenVoice(v.id)} style={{ cursor: "pointer", background: "#FDFAF5", display: "flex", gap: 0, overflow: "hidden", borderLeft: `3px solid ${c.color}` }}
        onMouseEnter={e => e.currentTarget.style.opacity = "0.85"}
        onMouseLeave={e => e.currentTarget.style.opacity = "1"}>
        {v.imageUrl && (
          <div style={{ width: 80, flexShrink: 0, background: v.gradient, position: "relative" }}>
            <img src={v.imageUrl} alt="" style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover" }} onError={e => e.target.style.display="none"} />
          </div>
        )}
        <div style={{ padding: "12px 14px", flex: 1 }}>
          <span style={{ display: "inline-block", background: c.bg, color: c.color, padding: "1px 6px", borderRadius: 2, fontSize: 8, fontWeight: 800, textTransform: "uppercase", marginBottom: 6 }}>{c.label}</span>
          <h4 style={{ fontFamily: "Playfair Display, serif", fontSize: 13, fontWeight: 700, lineHeight: 1.35, color: "#1A1208", marginBottom: 6 }}>{v.headline}</h4>
          <span style={{ fontFamily: "Playfair Display, serif", fontSize: 11, fontWeight: 600, fontStyle: "italic", color: "#A09488" }}>{v.signature}</span>
        </div>
      </div>
    );
  };

  const QuestionCard = ({ q }) => {
    const c = cat(q.category);
    const myVote    = votes[q.id];
    const myOverlay = overlays[q.id];
    const myOp      = overlayOp[q.id] || 0;
    return (
      <div style={{ background: "#FDFAF5", borderLeft: `4px solid ${c.color}`, padding: "16px 18px", position: "relative", overflow: "hidden", display: "flex", flexDirection: "column", height: "100%" }}>
        {myOverlay && (
          <div style={{ position: "absolute", inset: 0, zIndex: 20, background: myOverlay === "yes" ? "rgba(21,92,42,0.88)" : "rgba(122,21,21,0.88)", opacity: myOp, transition: myOp === 1 ? "opacity 0.25s" : "opacity 0.45s", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 6, pointerEvents: "none" }}>
            <span style={{ fontSize: 36, color: "white" }}>{myOverlay === "yes" ? "✓" : "✗"}</span>
            <span style={{ fontFamily: "Inter, sans-serif", fontSize: 28, fontWeight: 800, color: "white", letterSpacing: "4px" }}>{myOverlay === "yes" ? "YES" : "NO"}</span>
          </div>
        )}
        <CategoryBadge categoryKey={q.category} />
        <h3 style={{ fontFamily: "Playfair Display, serif", fontSize: 14, fontWeight: 700, lineHeight: 1.4, color: "#1A1208", margin: "10px 0 12px", flex: 1 }}>{q.question}</h3>
        {!myVote ? (
          <>
            <div style={{ display: "flex", gap: 5, marginBottom: 8 }}>
              {[
                { key: "yes", label: "✓ Yes", hC: "#155C2A", hBg: "#E8F5EC" },
                { key: "no",  label: "✗ No",  hC: "#7A1515", hBg: "#FAE8E8" },
                { key: "unsure", label: "Unsure", hC: "#5A4A3A", hBg: "#F0EBE3" },
              ].map(({ key, label, hC, hBg }) => (
                <button key={key} onClick={() => key === "unsure" ? setVotes(v => ({...v, [q.id]: "unsure"})) : fireVote(q.id, key)}
                  style={{ flex: 1, padding: "6px 2px", border: "1px solid #D4CAB8", borderRadius: 5, background: "#F5F0E8", color: "#7A7068", fontSize: 10, fontWeight: 700, cursor: "pointer", fontFamily: "Inter", transition: "all 0.15s" }}
                  onMouseEnter={e => { e.currentTarget.style.background = hBg; e.currentTarget.style.color = hC; }}
                  onMouseLeave={e => { e.currentTarget.style.background = "#F5F0E8"; e.currentTarget.style.color = "#7A7068"; }}>
                  {label}
                </button>
              ))}
            </div>
            <PollBar poll={q.poll} />
          </>
        ) : (
          <>
            <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 6 }}>
              <span style={{ fontSize: 11, fontWeight: 700, color: myVote === "yes" ? "#155C2A" : myVote === "no" ? "#7A1515" : "#5A4A3A" }}>
                {myVote === "yes" ? "✓ Yes" : myVote === "no" ? "✗ No" : "Unsure"}
              </span>
              <button onClick={() => setVotes(v => ({...v, [q.id]: null}))} style={{ fontSize: 9, color: "#B8AFA4", background: "none", border: "none", cursor: "pointer", textDecoration: "underline", fontFamily: "Inter" }}>Change</button>
            </div>
            <PollBar poll={q.poll} />
          </>
        )}
        <div style={{ display: "flex", gap: 10, marginTop: 8, paddingTop: 8, borderTop: "1px solid #EAE4DA", alignItems: "center" }}>
          <span style={{ fontSize: 10, color: "#A09488" }}>{fmt(q.responses)} responses</span>
          <button onClick={() => onOpenQuestion(q.id)} style={{ marginLeft: "auto", background: "none", border: "none", cursor: "pointer", fontSize: 10, fontWeight: 700, color: "#1C3A5E", fontFamily: "Inter" }}>Read →</button>
        </div>
      </div>
    );
  };

  const RULE = <div style={{ background: "#C0B8AE", height: "1px", margin: "0" }} />;
  const COL_RULE = { borderRight: "1px solid #C0B8AE" };

  return (
    <div style={{ minHeight: "100vh", background: "#EDE8DF", fontFamily: "Inter, sans-serif" }}>
      <style>{FONTS}</style>
      <style>{`.no-hover { transition: opacity 0.15s; }`}</style>

      {/* ── MASTHEAD ── */}
      <header style={{ background: "linear-gradient(180deg, #0F1F3D 0%, #142544 100%)", boxShadow: "0 2px 16px rgba(0,0,0,0.3)" }}>
        <div style={{ maxWidth: 1380, margin: "0 auto", padding: "0 32px", height: 72, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <div style={{ display: "flex", gap: 20, alignItems: "center" }}>
            {[["all","All"],["global","Global"],["regional","Regional"],["local","Local"]].map(([k, l]) => (
              <button key={k} onClick={() => setActiveRing(k)}
                style={{ background: "none", border: "none", cursor: "pointer", fontFamily: "Inter", fontSize: 11, fontWeight: 700, color: activeRing === k ? "#FFFFFF" : "rgba(255,255,255,0.38)", borderBottom: activeRing === k ? "2px solid #FFFFFF" : "2px solid transparent", padding: "4px 0", transition: "color 0.15s", letterSpacing: "0.3px", textTransform: "uppercase" }}>
                {l}
              </button>
            ))}
          </div>
          <span style={{ fontFamily: "Playfair Display, serif", color: "#FFFFFF", fontSize: 52, fontWeight: 700, letterSpacing: "-2px" }}>Union</span>
          <div style={{ display: "flex", gap: 16, alignItems: "center" }}>
            <button onClick={onGoSaved} style={{ background: "none", border: "none", cursor: "pointer", color: bookmarks.length > 0 ? "#F5C842" : "rgba(255,255,255,0.38)", fontSize: 20 }}>
              {bookmarks.length > 0 ? "★" : "☆"}
            </button>
            <button onClick={onCreate} style={{ background: "rgba(255,255,255,0.1)", border: "1px solid rgba(255,255,255,0.2)", borderRadius: 4, padding: "7px 16px", color: "#FFFFFF", fontSize: 11, cursor: "pointer", fontFamily: "Inter", fontWeight: 700, letterSpacing: "0.3px" }}>+ Create</button>
            <button onClick={onGoAbout} style={{ background: "none", border: "none", cursor: "pointer", fontFamily: "Playfair Display, serif", fontSize: 12, color: "rgba(255,255,255,0.38)", fontStyle: "italic" }}
              onMouseEnter={e => e.currentTarget.style.color = "rgba(255,255,255,0.8)"}
              onMouseLeave={e => e.currentTarget.style.color = "rgba(255,255,255,0.38)"}>
              What we stand for
            </button>
          </div>
        </div>
        <div style={{ borderTop: "1px solid rgba(255,255,255,0.08)", padding: "5px 0", textAlign: "center" }}>
          <span style={{ fontSize: 9, color: "rgba(255,255,255,0.35)", letterSpacing: "1.5px", textTransform: "uppercase", fontWeight: 700 }}>{today} · Verified voices from around the world</span>
        </div>
      </header>

      <div style={{ maxWidth: 1380, margin: "0 auto", padding: "0 24px 60px" }}>

        {/* ── ROW 1: Lead voice + 2 featured side by side ── */}
        {lead && (
          <>
            <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: "1px", background: "#C0B8AE", marginTop: 24 }}>
              <LeadCard v={lead} />
              <div style={{ display: "flex", flexDirection: "column", gap: "1px", background: "#C0B8AE" }}>
                {featured.map(v => <FeaturedCard key={v.id} v={v} />)}
              </div>
            </div>

            {/* Section divider */}
            <div style={{ display: "flex", alignItems: "center", gap: 0, margin: "20px 0 0" }}>
              <div style={{ height: 2, width: 32, background: "#1A1208" }} />
              <span style={{ fontSize: 9, fontWeight: 900, textTransform: "uppercase", letterSpacing: "2px", color: "#1A1208", padding: "0 12px" }}>More Voices</span>
              <div style={{ flex: 1, height: 1, background: "#C0B8AE" }} />
            </div>

            {/* ── ROW 2: 4 standard voice cards ── */}
            <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: "1px", background: "#C0B8AE", marginTop: 0 }}>
              {standard.map(v => <StandardCard key={v.id} v={v} />)}
            </div>
          </>
        )}

        {/* ── QUESTIONS SECTION ── */}
        <div style={{ display: "flex", alignItems: "center", gap: 0, margin: "20px 0 0" }}>
          <div style={{ height: 2, width: 32, background: "#7A1515" }} />
          <span style={{ fontSize: 9, fontWeight: 900, textTransform: "uppercase", letterSpacing: "2px", color: "#7A1515", padding: "0 12px" }}>Today's Questions</span>
          <div style={{ flex: 1, height: 1, background: "#C0B8AE" }} />
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: "1px", background: "#C0B8AE" }}>
          {questionList.slice(0, 8).map(q => <QuestionCard key={q.id} q={q} />)}
        </div>

        {/* ── MORE VOICES: small cards ── */}
        {smallVoices.length > 0 && (
          <>
            <div style={{ display: "flex", alignItems: "center", gap: 0, margin: "20px 0 0" }}>
              <div style={{ height: 2, width: 32, background: "#1C3A5E" }} />
              <span style={{ fontSize: 9, fontWeight: 900, textTransform: "uppercase", letterSpacing: "2px", color: "#1C3A5E", padding: "0 12px" }}>Further reading</span>
              <div style={{ flex: 1, height: 1, background: "#C0B8AE" }} />
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: "1px", background: "#C0B8AE" }}>
              {smallVoices.map(v => <SmallVoiceCard key={v.id} v={v} />)}
            </div>
          </>
        )}

        {/* ── MORE QUESTIONS ── */}
        {questionList.length > 8 && (
          <>
            <div style={{ display: "flex", alignItems: "center", gap: 0, margin: "20px 0 0" }}>
              <div style={{ height: 2, width: 32, background: "#7A1515" }} />
              <span style={{ fontSize: 9, fontWeight: 900, textTransform: "uppercase", letterSpacing: "2px", color: "#7A1515", padding: "0 12px" }}>More questions</span>
              <div style={{ flex: 1, height: 1, background: "#C0B8AE" }} />
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: "1px", background: "#C0B8AE" }}>
              {questionList.slice(8).map(q => <QuestionCard key={q.id} q={q} />)}
            </div>
          </>
        )}

        <div style={{ textAlign: "center", padding: "32px 0 0", borderTop: "1px solid #D4CAB8", marginTop: 24 }}>
          <button onClick={onGoAbout} style={{ background: "none", border: "none", cursor: "pointer", fontFamily: "Playfair Display, serif", fontSize: 13, color: "#B8AFA4", fontStyle: "italic" }}
            onMouseEnter={e => e.currentTarget.style.color = "#1C3A5E"}
            onMouseLeave={e => e.currentTarget.style.color = "#B8AFA4"}>
            What Union stands for →
          </button>
          <p style={{ fontSize: 10, color: "#C8C0B4", marginTop: 6, letterSpacing: "0.5px" }}>Est. 2026 · Non-profit · No ads · No agenda · Forever</p>
        </div>
      </div>
    </div>
  );
}

function SideMenu({ open, onClose, activeTab, onSetTab, activeRing, onSetRing, onGoSaved, onGoAbout, onCreate, onGoArchive, bookmarks }) {
  return (
    <>
      {/* Backdrop */}
      {open && <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)", zIndex: 300, backdropFilter: "blur(2px)" }} />}
      {/* Panel */}
      <div style={{
        position: "fixed", top: 0, right: 0, bottom: 0, width: 280, zIndex: 400,
        background: "#0F1F3D",
        transform: open ? "translateX(0)" : "translateX(100%)",
        transition: "transform 0.3s ease",
        boxShadow: open ? "-4px 0 24px rgba(0,0,0,0.4)" : "none",
        display: "flex", flexDirection: "column",
      }}>
        {/* Close */}
        <div style={{ padding: "18px 20px", display: "flex", justifyContent: "flex-end", borderBottom: "1px solid rgba(255,255,255,0.08)" }}>
          <button onClick={onClose} style={{ background: "none", border: "none", color: "rgba(255,255,255,0.5)", fontSize: 22, cursor: "pointer", lineHeight: 1 }}>✕</button>
        </div>

        <div style={{ flex: 1, overflowY: "auto", padding: "8px 0" }}>
          {/* Content tabs */}
          <div style={{ padding: "8px 20px 4px" }}>
            <p style={{ fontSize: 9, fontWeight: 700, textTransform: "uppercase", letterSpacing: "1px", color: "rgba(255,255,255,0.3)", marginBottom: 10 }}>Browse</p>
            {[
              { key: "questions", label: "Questions", icon: null },
              { key: "voices",    label: "Voices",    icon: null },
              { key: "archive",   label: "Archive",   icon: null },
            ].map(({ key, label, icon }) => (
              <button key={key}
                onClick={() => { key === "archive" ? onGoArchive() : onSetTab(key); onClose(); }}
                style={{ width: "100%", display: "flex", alignItems: "center", gap: 14, padding: "13px 14px", background: activeTab === key ? "rgba(255,255,255,0.1)" : "none", border: "none", borderRadius: 8, cursor: "pointer", fontFamily: "Inter", marginBottom: 4, textAlign: "left" }}>
                {icon && <span style={{ fontSize: 16, width: 24, textAlign: "center" }}>{icon}</span>}
                <span style={{ fontSize: 14, fontWeight: 600, color: activeTab === key ? "#FFFFFF" : "rgba(255,255,255,0.6)" }}>{label}</span>
              </button>
            ))}
          </div>

          <div style={{ height: 1, background: "rgba(255,255,255,0.08)", margin: "12px 20px" }} />

          {/* Ring filter */}
          <div style={{ padding: "4px 20px" }}>
            <p style={{ fontSize: 9, fontWeight: 700, textTransform: "uppercase", letterSpacing: "1px", color: "rgba(255,255,255,0.3)", marginBottom: 10 }}>Filter by ring</p>
            {[
              { key: "all",      label: "All Rings",  sub: "Everything"  },
              { key: "global",   label: "Global",     sub: "Worldwide"   },
              { key: "regional", label: "Regional",   sub: "Ontario"     },
              { key: "local",    label: "Local",      sub: "Toronto"     },
            ].map(({ key, label, sub }) => (
              <button key={key}
                onClick={() => { onSetRing(key); onClose(); }}
                style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between", padding: "12px 14px", background: activeRing === key ? "rgba(255,255,255,0.1)" : "none", border: "none", borderRadius: 8, cursor: "pointer", fontFamily: "Inter", marginBottom: 4 }}>
                <span style={{ fontSize: 14, fontWeight: 600, color: activeRing === key ? "#FFFFFF" : "rgba(255,255,255,0.6)" }}>{label}</span>
                <span style={{ fontSize: 11, color: "rgba(255,255,255,0.35)" }}>{sub}</span>
              </button>
            ))}
          </div>

          <div style={{ height: 1, background: "rgba(255,255,255,0.08)", margin: "12px 20px" }} />

          {/* Actions */}
          <div style={{ padding: "4px 20px" }}>
            {[
              { label: `${bookmarks.length > 0 ? "★" : "☆"} Saved${bookmarks.length > 0 ? ` (${bookmarks.length})` : ""}`, fn: () => { onGoSaved(); onClose(); } },
              { label: "+ Create",           fn: () => { onCreate(); onClose(); } },
              { label: "What we stand for",  fn: () => { onGoAbout(); onClose(); } },
            ].map(({ label, fn }) => (
              <button key={label} onClick={fn}
                style={{ width: "100%", display: "flex", alignItems: "center", padding: "13px 14px", background: "none", border: "none", borderRadius: 8, cursor: "pointer", fontFamily: "Inter", marginBottom: 4, textAlign: "left" }}>
                <span style={{ fontSize: 14, fontWeight: 500, color: "rgba(255,255,255,0.6)" }}>{label}</span>
              </button>
            ))}
          </div>
        </div>

        <div style={{ padding: "16px 20px", borderTop: "1px solid rgba(255,255,255,0.08)" }}>
          <p style={{ fontSize: 10, color: "rgba(255,255,255,0.2)", textAlign: "center" }}>Union · Non-profit · Est. 2026</p>
        </div>
      </div>
    </>
  );
}

// ─── MAIN VIEW ────────────────────────────────────────────────────────────────

function MainView({ onOpenQuestion, onOpenVoice, onCreate, onGoAbout, onGoArchive, onGoSaved, bookmarks, onBookmark }) {
  const [activeTab, setActiveTab]     = useState("voices");
  const [activeRing, setActiveRing]   = useState("all");
  const [menuOpen, setMenuOpen]       = useState(false);
  const [headerVisible, setHeaderVisible] = useState(true);
  const lastScrollY = useRef(0);
  const HEADER_H = 56;

  const onVScroll = (e) => {
    const y = e.target.scrollTop;
    if (y > lastScrollY.current && y > 60)  setHeaderVisible(false);
    else if (y < lastScrollY.current)        setHeaderVisible(true);
    lastScrollY.current = y;
  };

  const items = activeTab === "questions"
    ? (activeRing === "all" ? questions : questions.filter(q => q.ring === activeRing))
    : (activeRing === "all" ? voices    : voices.filter(v => v.ring === activeRing));

  return (
    <div style={{ width: "100%", height: "100vh", overflow: "hidden", fontFamily: "Inter, sans-serif", position: "relative" }}>
      <style>{FONTS}</style>

      <SideMenu open={menuOpen} onClose={() => setMenuOpen(false)}
        activeTab={activeTab} onSetTab={setActiveTab}
        activeRing={activeRing} onSetRing={setActiveRing}
        onGoSaved={onGoSaved} onGoAbout={onGoAbout} onCreate={onCreate}
        onGoArchive={onGoArchive} bookmarks={bookmarks} />

      {/* HEADER — clean, just Union + hamburger */}
      <div style={{
        position: "fixed", top: 0, left: 0, right: 0, zIndex: 200,
        transform: `translateY(${headerVisible ? 0 : -HEADER_H}px)`,
        transition: "transform 0.3s ease",
        background: "linear-gradient(180deg, #0F1F3D 0%, #142544 100%)",
        boxShadow: "0 2px 16px rgba(0,0,0,0.3)",
        height: HEADER_H,
        display: "flex", alignItems: "center", justifyContent: "space-between",
        padding: "0 20px",
      }}>
        <div style={{ minWidth: 40 }} />
        <span style={{ fontFamily: "Playfair Display, serif", color: "#FFFFFF", fontSize: 36, fontWeight: 700, letterSpacing: "-1.5px", lineHeight: 1 }}>Union</span>
        <button onClick={() => setMenuOpen(true)}
          style={{ background: "none", border: "none", cursor: "pointer", padding: "8px", display: "flex", flexDirection: "column", gap: 5, minWidth: 40, alignItems: "flex-end" }}>
          <span style={{ display: "block", width: 22, height: 2, background: "#FFFFFF", borderRadius: 1 }} />
          <span style={{ display: "block", width: 16, height: 2, background: "#FFFFFF", borderRadius: 1 }} />
          <span style={{ display: "block", width: 22, height: 2, background: "#FFFFFF", borderRadius: 1 }} />
        </button>
      </div>

      {/* VERTICAL SCROLL COLUMN */}
      <div onScroll={onVScroll} className="union-scroll"
        style={{ width: "100%", height: "100vh", overflowY: "auto", scrollSnapType: "y mandatory", WebkitOverflowScrolling: "touch", msOverflowStyle: "none", scrollbarWidth: "none" }}>
        {items.length === 0 ? (
          <div style={{ height: "100vh", display: "flex", alignItems: "center", justifyContent: "center", paddingTop: HEADER_H }}>
            <div style={{ textAlign: "center" }}>
              <p style={{ fontFamily: "Playfair Display, serif", fontSize: 22, color: "#B8AFA4", fontStyle: "italic", marginBottom: 8 }}>Nothing here yet.</p>
              <p style={{ fontSize: 13, color: "#C0B8AE" }}>Be the first to contribute.</p>
            </div>
          </div>
        ) : items.map(item => (
          activeTab === "questions"
            ? <QuestionCard key={item.id} q={item} headerH={HEADER_H} onOpen={onOpenQuestion} bookmarks={bookmarks} onBookmark={onBookmark} />
            : <VoiceCard    key={item.id} v={item} headerH={HEADER_H} onOpen={onOpenVoice}    bookmarks={bookmarks} onBookmark={onBookmark} />
        ))}
      </div>
    </div>
  );
}

// ─── BOOKMARK BUTTON ──────────────────────────────────────────────────────────

function BookmarkBtn({ id, type, bookmarks, onBookmark }) {
  const saved = bookmarks.some(b => b.id === id && b.type === type);
  return (
    <button onClick={e => { e.stopPropagation(); onBookmark({ id, type }); }}
      style={{ background: saved ? "rgba(245,200,66,0.15)" : "rgba(0,0,0,0.06)", border: `1px solid ${saved ? "#F5C842" : "rgba(0,0,0,0.1)"}`, borderRadius: 6, padding: "6px 10px", cursor: "pointer", fontSize: 15, lineHeight: 1, color: saved ? "#F5C842" : "#B8AFA4", transition: "all 0.15s", flexShrink: 0 }}>
      {saved ? "★" : "☆"}
    </button>
  );
}

// ─── QUESTION CARD ────────────────────────────────────────────────────────────

function QuestionCard({ q, headerH, onOpen, bookmarks, onBookmark }) {
  const [vote, setVote]               = useState(null);
  const [overlay, setOverlay]         = useState(null);   // "yes" | "no" | null
  const [overlayOpacity, setOverlayOpacity] = useState(0);
  const [dragX, setDragX]             = useState(0);
  const touchStart = useRef(null);
  const axis = useRef(null);
  const c = cat(q.category);

  const fireVote = (v) => {
    if (overlay) return; // block while animation is running
    setVote(null); // clear current vote before animation
    // Phase 1: overlay fades in
    setOverlay(v);
    setTimeout(() => setOverlayOpacity(1), 20);
    // Phase 2: overlay fades out — hold for ~1.4s
    setTimeout(() => setOverlayOpacity(0), 1400);
    // Phase 3: set vote and remove overlay
    setTimeout(() => { setVote(v); setOverlay(null); }, 1900);
  };

  const onTouchStart = (e) => {
    touchStart.current = { x: e.touches[0].clientX, y: e.touches[0].clientY };
    axis.current = null;
  };
  const onTouchMove = (e) => {
    if (!touchStart.current) return;
    const dx = e.touches[0].clientX - touchStart.current.x;
    const dy = e.touches[0].clientY - touchStart.current.y;
    if (!axis.current && (Math.abs(dx) > 8 || Math.abs(dy) > 8))
      axis.current = Math.abs(dx) > Math.abs(dy) ? "h" : "v";
    if (axis.current === "h") { e.preventDefault(); setDragX(dx); }
  };
  const onTouchEnd = (e) => {
    if (touchStart.current && axis.current === "h") {
      const dx = e.changedTouches[0].clientX - touchStart.current.x;
      if (!overlay && Math.abs(dx) > 70) {
        const direction = dx > 0 ? "yes" : "no";
        // Allow swipe to change vote if already voted the other way
        if (!vote || vote !== direction) fireVote(direction);
      }
    }
    setDragX(0); axis.current = null; touchStart.current = null;
  };

  // Subtle drag tint — no card movement
  const dragTint = dragX > 40
    ? `rgba(21,92,42,${Math.min(dragX / 220, 0.22)})`
    : dragX < -40
      ? `rgba(122,21,21,${Math.min(-dragX / 220, 0.22)})`
      : "transparent";

  return (
    <div style={{ scrollSnapAlign: "start", height: "100vh", paddingTop: headerH, display: "flex", flexDirection: "column", background: "#EDE8DF", backgroundImage: "radial-gradient(circle at 1px 1px, rgba(120,100,80,0.07) 1px, transparent 0)", backgroundSize: "24px 24px" }}
      onTouchStart={onTouchStart} onTouchMove={onTouchMove} onTouchEnd={onTouchEnd}>

      <div style={{ flex: 1, margin: "14px 20px", background: "#FDFAF5", border: `1px solid #D4CAB8`, borderLeft: `6px solid ${c.color}`, borderRadius: "0 14px 14px 0", padding: "22px 20px", boxShadow: "0 4px 24px rgba(0,0,0,0.09)", display: "flex", flexDirection: "column", overflow: "hidden", position: "relative" }}>

        {/* Drag tint — subtle, no movement */}
        {dragTint !== "transparent" && (
          <div style={{ position: "absolute", inset: 0, background: dragTint, borderRadius: "0 14px 14px 0", pointerEvents: "none", zIndex: 5 }} />
        )}

        {/* Vote overlay — floods the card, then fades */}
        {overlay && (
          <div style={{
            position: "absolute", inset: 0, zIndex: 30,
            borderRadius: "0 14px 14px 0",
            background: overlay === "yes" ? "rgba(21,92,42,0.82)" : "rgba(122,21,21,0.82)",
            opacity: overlayOpacity,
            transition: overlayOpacity === 1 ? "opacity 0.25s ease" : "opacity 0.45s ease",
            display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 8,
            pointerEvents: "none",
          }}>
            <span style={{ fontSize: 72, color: "white", lineHeight: 1 }}>
              {overlay === "yes" ? "✓" : "✗"}
            </span>
            <span style={{ fontFamily: "Inter, sans-serif", fontSize: 52, fontWeight: 800, color: "white", letterSpacing: "4px" }}>
              {overlay === "yes" ? "YES" : "NO"}
            </span>
          </div>
        )}

        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 14 }}>
          <CategoryBadge categoryKey={q.category} />
          <BookmarkBtn id={q.id} type="question" bookmarks={bookmarks} onBookmark={onBookmark} />
        </div>

        <h1 style={{ fontFamily: "Playfair Display, serif", fontSize: 22, fontWeight: 900, lineHeight: 1.28, color: "#1A1208", marginBottom: 16 }}>{q.question}</h1>

        {q.topResponse && (
          <div style={{ flex: 1, display: "flex", gap: 12, alignItems: "flex-start", marginBottom: 16, minHeight: 0 }}>
            <Avatar categoryKey={q.category} hasVideo={q.topResponse.hasVideo} />
            <div style={{ flex: 1 }}>
              <p style={{ fontFamily: "Playfair Display, serif", fontSize: 13.5, fontStyle: "italic", lineHeight: 1.6, color: "#3A322A", marginBottom: 6 }}>"{q.topResponse.quote}"</p>
              <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                <span style={{ fontSize: 11, color: "#A09488", fontWeight: 600 }}>{q.topResponse.region}</span>
                {q.topResponse.affected && <span style={{ fontSize: 8, fontWeight: 700, color: "#7A1515", background: "#FAE8E8", padding: "1px 6px", borderRadius: 8, textTransform: "uppercase" }}>Directly affected</span>}
              </div>
            </div>
          </div>
        )}

        {!vote && !overlay ? (
          <div style={{ marginBottom: 16 }}>
            <p style={{ fontSize: 10, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.7px", color: "#A09488", marginBottom: 10 }}>Cast your vote</p>
            <div style={{ display: "flex", gap: 8 }}>
              {[
                { key: "yes",    label: "✓  Yes",    hC: "#155C2A", hBg: "#E8F5EC", hBr: "#AADCBC" },
                { key: "no",     label: "✗  No",     hC: "#7A1515", hBg: "#FAE8E8", hBr: "#E8BCBC" },
                { key: "unsure", label: "Unsure", hC: "#5A4A3A", hBg: "#F0EBE3", hBr: "#C8B8A4" },
              ].map(({ key, label, hC, hBg, hBr }) => (
                <button key={key} onClick={() => key === "unsure" ? setVote("unsure") : fireVote(key)}
                  style={{ flex: 1, padding: "12px 4px", border: "1.5px solid #D4CAB8", borderRadius: 8, background: "#F5F0E8", color: "#7A7068", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "Inter", transition: "all 0.15s" }}
                  onMouseEnter={e => { e.currentTarget.style.borderColor = hBr; e.currentTarget.style.background = hBg; e.currentTarget.style.color = hC; }}
                  onMouseLeave={e => { e.currentTarget.style.borderColor = "#D4CAB8"; e.currentTarget.style.background = "#F5F0E8"; e.currentTarget.style.color = "#7A7068"; }}>
                  {label}
                </button>
              ))}
            </div>
          </div>
        ) : vote ? (
          <div style={{ marginBottom: 16 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10 }}>
              <span style={{ fontSize: 13, fontWeight: 700, color: vote === "yes" ? "#155C2A" : vote === "no" ? "#7A1515" : "#5A4A3A" }}>
                {vote === "yes" ? "✓ You voted Yes" : vote === "no" ? "✗ You voted No" : "You voted Unsure"}
              </span>
              <button onClick={() => setVote(null)} style={{ fontSize: 10, color: "#B8AFA4", background: "none", border: "none", cursor: "pointer", fontFamily: "Inter", textDecoration: "underline" }}>Change</button>
            </div>
            <PollBar poll={q.poll} />
          </div>
        ) : <div style={{ marginBottom: 16, height: 60 }} />}

        <div style={{ paddingTop: 12, borderTop: "1px solid #EAE4DA", display: "flex", alignItems: "center", gap: 14 }}>
          <span style={{ fontSize: 12, color: "#A09488" }}>{fmt(q.responses)} responses</span>
          <span style={{ fontSize: 12, color: "#7A1515", fontWeight: 600 }}>{fmt(q.directlyAffected)} affected</span>
          <button onClick={() => onOpen(q.id)} style={{ marginLeft: "auto", background: "none", border: "none", cursor: "pointer", fontSize: 13, fontWeight: 700, color: "#1C3A5E", fontFamily: "Inter" }}>Read responses →</button>
        </div>
      </div>
    </div>
  );
}

